{"code":"const issues = linear__list_issues({ state: "in_progress" });
const counts = {};
for (const issue of issues) {
  counts[issue.assignee] = (counts[issue.assignee] || 0) + 1;
}
let max = 0, top = null;
for (const [assignee, count] of Object.entries(counts)) {
  if (count > max) { max = count; top = assignee; }
}
`${top} — ${max}`"}
